#include<bits/stdc++.h>
using namespace std;
int n,a[1010];
int dp[1010][1010][2];
const int mod=19650827;
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        dp[i][i][0]=1;
    }
    for(int len=2;len<=n;len++)
    {
        for(int l=1,r=len;r<=n;l++,r++)
        {
            if(a[l]<a[r])
            {
                dp[l][r][0]+=dp[l+1][r][1];
                dp[l][r][0]%=mod;
            }
            if(a[l]<a[l+1])
            {
                dp[l][r][0]+=dp[l+1][r][0];
                dp[l][r][0]%=mod;
            }
            if(a[r]>a[l])
            {
                dp[l][r][1]+=dp[l][r-1][0];
                dp[l][r][1]%=mod;
            }
            if(a[r]>a[r-1])
            {
                dp[l][r][1]+=dp[l][r-1][1];
                dp[l][r][1]%=mod;
            }
        }
    }
    printf("%d",(dp[1][n][0]+dp[1][n][1])%mod);
    return 0;
}
